const express = require('express');
const cors = require('cors');
const multer = require('multer');
const path = require('path');
const fs = require('fs');
const { execFile } = require('child_process');
const { promisify } = require('util');
const Anthropic = require('@anthropic-ai/sdk');
const Groq = require('groq-sdk');

const execFileAsync = promisify(execFile);

const app = express();
const PORT = 3100;

// CORS
app.use(cors({
  origin: [
    'https://mybotia.com',
    'https://app.mybotia.com',
    'https://voice.mybotia.com',
    'http://localhost:3100',
    'http://127.0.0.1:3100'
  ],
  credentials: true,
  exposedHeaders: ['X-Transcript', 'X-Response']
}));

app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

// Multer — audio upload vers /tmp
const upload = multer({
  dest: '/tmp/',
  limits: { fileSize: 25 * 1024 * 1024 }
});

// API Keys
const GROQ_API_KEY = '<GROQ_API_KEY>';
const ANTHROPIC_API_KEY = '<ANTHROPIC_OAUTH_TOKEN>';

const groq = new Groq({ apiKey: GROQ_API_KEY });
const anthropic = new Anthropic({ apiKey: ANTHROPIC_API_KEY });

const SYSTEM_PROMPT = `Tu es Léa, collaboratrice IA de Coach Digital Paris. \
Tu réponds de manière concise et professionnelle en français. \
Tu es spécialisée en juridique, administratif et commercial. \
Réponds en 2-3 phrases maximum pour que la réponse vocale reste fluide.`;

// Cleanup helper
function cleanupFile(filePath) {
  if (filePath) fs.unlink(filePath, () => {});
}

// POST /api/voice — pipeline STT → LLM → TTS
app.post('/api/voice', upload.single('audio'), async (req, res) => {
  const audioPath = req.file?.path;
  let ttsOutputPath = null;

  // Global timeout 30s
  const timeout = setTimeout(() => {
    if (!res.headersSent) {
      res.status(504).json({ error: 'Timeout dépassé (30s)' });
    }
    cleanupFile(audioPath); cleanupFile(audioPath + ".webm"); cleanupFile(audioPath + ".ogg");
    cleanupFile(ttsOutputPath);
  }, 30000);

  try {
    if (!audioPath) {
      clearTimeout(timeout);
      return res.status(400).json({ error: 'Aucun fichier audio reçu' });
    }

    // ── 0. Rename with extension for Groq ──────────────────────────────
    const ext = req.file?.mimetype?.includes('webm') ? '.webm' : 
                req.file?.mimetype?.includes('ogg') ? '.ogg' : 
                req.file?.mimetype?.includes('mp4') ? '.mp4' : '.webm';
    const renamedPath = audioPath + ext;
    fs.renameSync(audioPath, renamedPath);
    const audioFilePath = renamedPath;

    // ── 1. STT — Groq Whisper ─────────────────────────────────────────────
    console.log('[STT] Transcription en cours...');
    const transcription = await groq.audio.transcriptions.create({
      file: fs.createReadStream(audioFilePath),
      model: 'whisper-large-v3',
      language: 'fr',
      response_format: 'json'
    });

    const userText = transcription.text?.trim();
    if (!userText) {
      clearTimeout(timeout);
      cleanupFile(audioPath); cleanupFile(audioPath + ".webm"); cleanupFile(audioPath + ".ogg");
      return res.status(400).json({ error: 'Transcription vide — parlez plus fort' });
    }
    console.log(`[STT] "${userText}"`);

    // ── 2. LLM — Groq (Llama 3.3 70B) ──────────────────────────────────
    console.log('[LLM] Requête Groq...');
    const llmResponse = await groq.chat.completions.create({
      model: 'llama-3.3-70b-versatile',
      max_tokens: 300,
      messages: [
        { role: 'system', content: SYSTEM_PROMPT },
        { role: 'user', content: userText }
      ]
    });

    const responseText = llmResponse.choices[0].message.content;
    console.log(`[LLM] "${responseText}"`);

    // ── 3. TTS — edge-tts ─────────────────────────────────────────────────
    console.log('[TTS] Synthèse vocale...');
    ttsOutputPath = `/tmp/tts_${Date.now()}_${Math.random().toString(36).slice(2)}.mp3`;

    await execFileAsync('edge-tts', [
      '--voice', 'fr-FR-VivienneMultilingualNeural',
      '--rate=-4%',
      '--pitch=-2Hz',
      '--text', responseText,
      '--write-media', ttsOutputPath
    ], { timeout: 20000 });

    if (!fs.existsSync(ttsOutputPath)) {
      throw new Error('edge-tts n\'a pas produit de fichier audio');
    }

    // ── 4. Réponse ────────────────────────────────────────────────────────
    clearTimeout(timeout);

    res.setHeader('Content-Type', 'audio/mpeg');
    res.setHeader('X-Transcript', encodeURIComponent(userText));
    res.setHeader('X-Response', encodeURIComponent(responseText));

    const stream = fs.createReadStream(ttsOutputPath);
    stream.pipe(res);
    stream.on('end', () => {
      cleanupFile(audioPath); cleanupFile(audioPath + ".webm"); cleanupFile(audioPath + ".ogg");
      cleanupFile(ttsOutputPath);
    });
    stream.on('error', (err) => {
      console.error('[STREAM ERROR]', err);
      cleanupFile(audioPath); cleanupFile(audioPath + ".webm"); cleanupFile(audioPath + ".ogg");
      cleanupFile(ttsOutputPath);
    });

  } catch (err) {
    clearTimeout(timeout);
    console.error('[ERROR]', err.message || err);
    cleanupFile(audioPath); cleanupFile(audioPath + ".webm"); cleanupFile(audioPath + ".ogg");
    cleanupFile(ttsOutputPath);
    if (!res.headersSent) {
      res.status(500).json({ error: err.message || 'Erreur serveur' });
    }
  }
});

// Health check
app.get('/api/health', (req, res) => {
  res.json({ status: 'ok', service: 'voice-poc', port: PORT });
});

app.listen(PORT, '127.0.0.1', () => {
  console.log(`\n🎙  Voice POC — Léa`);
  console.log(`   Port    : ${PORT}`);
  console.log(`   URL     : http://localhost:${PORT}\n`);
});

