    statusDots.classList.add('hidden');
  },
  processing: () => {
    avatarRing.className = 'avatar-ring processing';
    micIcon.classList.add('hidden');
    stopIcon.classList.add('hidden');
    spinner.classList.remove('hidden');
    micBtn.disabled = true;
    micBtn.className = 'mic-btn processing';
    micBtnText.textContent = 'Traitement...';
    statusLabel.textContent = 'Réflexion';
    statusDots.classList.remove('hidden');
  },
  speaking: () => {
    avatarRing.className = 'avatar-ring speaking';
    micIcon.classList.remove('hidden');
    stopIcon.classList.add('hidden');
    spinner.classList.add('hidden');
    micBtn.disabled = false;
    micBtn.className = 'mic-btn';
    micBtnText.textContent = 'Parler';
    statusLabel.textContent = 'Léa répond...';
    statusDots.classList.add('hidden');
  }
};

// ── Mic permission & init ─────────────────────────────────────────────────
async function getMicStream() {
  if (!stream) {
    stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
  }
  return stream;
}

// ── Start recording ───────────────────────────────────────────────────────
async function startRecording() {
  if (isProcessing) return;

  // Stop any playing audio
  if (currentAudio) {
    currentAudio.pause();
    currentAudio = null;
  }

  try {
    const micStream = await getMicStream();
    audioChunks = [];

    // Pick best supported MIME type
    const mimeType = getSupportedMimeType();
    const options = mimeType ? { mimeType } : {};

    mediaRecorder = new MediaRecorder(micStream, options);

    mediaRecorder.ondataavailable = (e) => {
      if (e.data.size > 0) audioChunks.push(e.data);
    };

    mediaRecorder.onstop = handleRecordingStop;
    mediaRecorder.start(100); // collect every 100ms

    isRecording = true;
    states.recording();

  } catch (err) {
    console.error('Mic error:', err);
    if (err.name === 'NotAllowedError') {
      showToast('Accès au microphone refusé. Autorisez-le dans votre navigateur.');
    } else {
      showToast('Impossible d\'accéder au microphone : ' + err.message);
    }
  }
}

// ── Stop recording ────────────────────────────────────────────────────────
function stopRecording() {
  if (!mediaRecorder || !isRecording) return;
  isRecording = false;
  mediaRecorder.stop();
}

// ── Process audio ─────────────────────────────────────────────────────────
async function handleRecordingStop() {
  if (audioChunks.length === 0) {
    states.idle();
    return;
  }

  isProcessing = true;
  states.processing();

  const mimeType = mediaRecorder.mimeType || 'audio/webm';
  const blob = new Blob(audioChunks, { type: mimeType });
  const ext = mimeTypeToExt(mimeType);

  const formData = new FormData();
  formData.append('audio', blob, `recording.${ext}`);

  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 30000);

    const response = await fetch(API_URL, {
      method: 'POST',
      body: formData,
      signal: controller.signal
    });
    clearTimeout(timeout);

    if (!response.ok) {
      const err = await response.json().catch(() => ({ error: `HTTP ${response.status}` }));
      throw new Error(err.error || `Erreur serveur (${response.status})`);
    }

    // Extract headers
    const transcript = decodeHeader(response.headers.get('X-Transcript'));
    const leaResponse = decodeHeader(response.headers.get('X-Response'));

    // Update transcript UI
    if (transcript) {
      userText.textContent = transcript;
      userBlock.classList.remove('hidden');
      userBlock.className = 'transcript-block';
    }
    if (leaResponse) {
      leaText.textContent = leaResponse;
      leaBlock.classList.remove('hidden');
      leaBlock.className = 'transcript-block lea';
    }

    // Play audio response
    const audioBlob = await response.blob();
    await playAudioBlob(audioBlob);

  } catch (err) {
    console.error('[ERROR]', err);
    if (err.name === 'AbortError') {
      showToast('Timeout — la requête a pris trop longtemps');
    } else {
      showToast(err.message || 'Erreur inattendue');
    }
    states.idle();
  } finally {
    isProcessing = false;
  }
}

// ── Audio playback ────────────────────────────────────────────────────────
function playAudioBlob(blob) {
  return new Promise((resolve) => {
    const url = URL.createObjectURL(blob);
    currentAudio = new Audio(url);

    states.speaking();

    currentAudio.onended = () => {
      URL.revokeObjectURL(url);
      currentAudio = null;
      states.idle();
      resolve();
    };

    currentAudio.onerror = (e) => {
      console.error('Audio playback error:', e);
      URL.revokeObjectURL(url);
      currentAudio = null;
      states.idle();
      resolve();
    };

    currentAudio.play().catch((err) => {
      console.error('play() failed:', err);
      states.idle();
      resolve();
    });
  });
}

// ── Button click handler ──────────────────────────────────────────────────
micBtn.addEventListener('click', () => {
  if (isProcessing) return;

  if (isRecording) {
    stopRecording();
  } else {
    // Stop current audio if playing
    if (currentAudio) {
      currentAudio.pause();
      currentAudio = null;
    }
    startRecording();
  }
});

// ── Helpers ───────────────────────────────────────────────────────────────
function getSupportedMimeType() {
  const types = [
    'audio/webm;codecs=opus',
    'audio/webm',
    'audio/ogg;codecs=opus',
    'audio/mp4',
  ];
  return types.find(t => MediaRecorder.isTypeSupported(t)) || '';
}

function mimeTypeToExt(mimeType) {
  if (mimeType.includes('webm')) return 'webm';
  if (mimeType.includes('ogg'))  return 'ogg';
  if (mimeType.includes('mp4'))  return 'mp4';
  return 'webm';
}

function decodeHeader(value) {
  if (!value) return '';
  try { return decodeURIComponent(value); }
  catch { return value; }
}

function showToast(message) {
  // Remove existing toasts
  document.querySelectorAll('.toast').forEach(t => t.remove());

  const toast = document.createElement('div');
  toast.className = 'toast';
  toast.textContent = message;
  document.body.appendChild(toast);

  setTimeout(() => {
    if (toast.parentNode) toast.remove();
  }, 4200);
}

// ── Init ──────────────────────────────────────────────────────────────────
states.idle();

// Pre-warm mic permission on first interaction (optional UX improvement)
document.addEventListener('click', () => {
  if (!stream && !isRecording) {
    getMicStream().catch(() => {}); // silent fail, will prompt on btn click
  }
}, { once: true });

